{
    "level": "B1",
    "intro": "W tym temacie nauczysz się typowej angielskiej kolejności: <strong>opinion, size, age, shape, color, origin, material, purpose</strong>.",
    "rules": [
        {
            "label": "TYPOWA KOLEJNOŚĆ",
            "color": "emerald",
            "text": "Najczęstszy układ to <strong>opinion → size → age → shape → color → origin → material → purpose</strong>.",
            "example": "a lovely small old round brown Italian wooden table"
        },
        {
            "label": "NIE WSZYSTKIE MIEJSCA",
            "color": "blue",
            "text": "Nie trzeba zapełniać każdej pozycji. Większość zdań ma tylko jeden do trzech przymiotników.",
            "example": "a nice blue shirt"
        },
        {
            "label": "BLISKO RZECZOWNIKA",
            "color": "amber",
            "text": "<strong>Material</strong> i <strong>purpose</strong> często stoją najbliżej rzeczownika.",
            "example": "a black leather jacket / a sleeping bag"
        }
    ]
}

{
    "title": "1. Typowy porządek",
    "intro": "Zapamiętaj najczęstszą kolejność.",
    "items": [
        {
            "label": "1",
            "title": "opinion",
            "subtitle": "nice, ugly, beautiful"
        },
        {
            "label": "2",
            "title": "size",
            "subtitle": "big, small, tall"
        },
        {
            "label": "3",
            "title": "age / shape",
            "subtitle": "old, young, round, square"
        },
        {
            "label": "4",
            "title": "color / origin",
            "subtitle": "red, blue, Italian, Ukrainian"
        },
        {
            "label": "5",
            "title": "material / purpose",
            "subtitle": "wooden, metal, sleeping, racing"
        },
        {
            "label": "6",
            "title": "noun",
            "subtitle": "bag, table, shoes, car"
        }
    ]
}

{
    "title": "2. Jak to brzmi naturalnie",
    "sections": [
        {
            "label": "Krótkie naturalne frazy",
            "color": "emerald",
            "description": "W realnej mowie często wystarczą dwa albo trzy przymiotniki.",
            "examples": [
                {
                    "en": "a beautiful old house",
                    "ua": "piękny stary dom"
                },
                {
                    "en": "a small black dog",
                    "ua": "mały czarny pies"
                },
                {
                    "en": "an expensive Italian car",
                    "ua": "drogi włoski samochód"
                }
            ]
        },
        {
            "label": "Dłuższe łańcuchy",
            "color": "blue",
            "description": "Gdy przymiotników jest więcej, kolejność staje się ważniejsza.",
            "examples": [
                {
                    "en": "a lovely small old round table",
                    "ua": "uroczy mały stary okrągły stół"
                },
                {
                    "en": "a big modern glass office building",
                    "ua": "duży nowoczesny szklany budynek biurowy"
                },
                {
                    "en": "a stylish long black wool coat",
                    "ua": "stylowy długi czarny wełniany płaszcz"
                }
            ]
        },
        {
            "label": "Material i purpose przy rzeczowniku",
            "color": "amber",
            "description": "Słowa takie jak <strong>wooden, plastic, sleeping, racing</strong> zwykle stoją blisko rzeczownika.",
            "examples": [
                {
                    "en": "a large brown wooden box",
                    "ua": "duże brązowe drewniane pudełko"
                },
                {
                    "en": "a light blue sleeping bag",
                    "ua": "jasnoniebieski śpiwór"
                },
                {
                    "en": "a fast red racing bike",
                    "ua": "szybki czerwony rower wyścigowy"
                }
            ],
            "note": "Purpose adjectives często zachowują się prawie jak część rzeczownika."
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Nienaturalna kolejność.",
            "wrong": "a wooden old box",
            "right": "✅ <span class=\"font-mono\">an old wooden box</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Color przed size bez powodu.",
            "wrong": "a black small dog",
            "right": "✅ <span class=\"font-mono\">a small black dog</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Purpose zbyt daleko od rzeczownika.",
            "wrong": "a sleeping blue warm bag",
            "right": "✅ <span class=\"font-mono\">a warm blue sleeping bag</span>"
        }
    ]
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "Typowy układ: <strong>opinion → size → age → shape → color → origin → material → purpose → noun</strong>.",
        "W realnej mowie często wystarczą 1–3 przymiotniki.",
        "Color zwykle pojawia się po size / age / shape.",
        "Material i purpose często stoją najbliżej rzeczownika.",
        "Jeśli nie masz pewności, użyj mniej przymiotników, ale w naturalnej kolejności."
    ]
}

